import { randomBytes, createHash } from "crypto";

export interface XOAuthConfig {
  clientId: string;
  clientSecret?: string;
  redirectUri: string;
  scopes?: string[];
}

export interface XOAuthTokens {
  access_token: string;
  refresh_token: string;
  expires_in: number;
  scope: string;
  token_type: string;
}

export interface XUserProfile {
  id: string;
  name: string;
  username: string;
  profile_image_url?: string;
  verified?: boolean;
}

interface PKCEPair {
  codeVerifier: string;
  codeChallenge: string;
  state: string;
}

const X_AUTHORIZE_URL = "https://x.com/i/oauth2/authorize";
const X_TOKEN_URL = "https://api.x.com/2/oauth2/token";
const X_REVOKE_URL = "https://api.x.com/2/oauth2/revoke";
const X_USERS_ME_URL = "https://api.x.com/2/users/me";

const DEFAULT_SCOPES = [
  "tweet.read",
  "users.read",
  "follows.read",
  "dm.read",
  "dm.write",
  "offline.access",
];

export function generatePKCE(): PKCEPair {
  const codeVerifier = randomBytes(64).toString("base64url").slice(0, 128);
  const codeChallenge = createHash("sha256")
    .update(codeVerifier)
    .digest("base64url");
  const state = randomBytes(32).toString("hex");
  return { codeVerifier, codeChallenge, state };
}

export function buildAuthorizeUrl(
  config: XOAuthConfig,
  pkce: PKCEPair
): string {
  const params = new URLSearchParams({
    response_type: "code",
    client_id: config.clientId,
    redirect_uri: config.redirectUri,
    scope: (config.scopes ?? DEFAULT_SCOPES).join(" "),
    state: pkce.state,
    code_challenge: pkce.codeChallenge,
    code_challenge_method: "S256",
  });
  return `${X_AUTHORIZE_URL}?${params.toString()}`;
}

export async function exchangeCodeForTokens(
  config: XOAuthConfig,
  code: string,
  codeVerifier: string
): Promise<XOAuthTokens> {
  const body = new URLSearchParams({
    code,
    grant_type: "authorization_code",
    client_id: config.clientId,
    redirect_uri: config.redirectUri,
    code_verifier: codeVerifier,
  });

  const headers: Record<string, string> = {
    "Content-Type": "application/x-www-form-urlencoded",
  };

  // Confidential clients must send client_secret via Basic auth
  if (config.clientSecret) {
    const credentials = Buffer.from(
      `${config.clientId}:${config.clientSecret}`
    ).toString("base64");
    headers["Authorization"] = `Basic ${credentials}`;
  }

  const res = await fetch(X_TOKEN_URL, {
    method: "POST",
    headers,
    body: body.toString(),
  });

  if (!res.ok) {
    const err = await res.text();
    throw new Error(`X token exchange failed (${res.status}): ${err}`);
  }

  return res.json();
}

export async function refreshTokens(
  config: XOAuthConfig,
  refreshToken: string
): Promise<XOAuthTokens> {
  const body = new URLSearchParams({
    grant_type: "refresh_token",
    refresh_token: refreshToken,
    client_id: config.clientId,
  });

  const headers: Record<string, string> = {
    "Content-Type": "application/x-www-form-urlencoded",
  };

  if (config.clientSecret) {
    const credentials = Buffer.from(
      `${config.clientId}:${config.clientSecret}`
    ).toString("base64");
    headers["Authorization"] = `Basic ${credentials}`;
  }

  const res = await fetch(X_TOKEN_URL, {
    method: "POST",
    headers,
    body: body.toString(),
  });

  if (!res.ok) {
    const err = await res.text();
    throw new Error(`X token refresh failed (${res.status}): ${err}`);
  }

  return res.json();
}

export async function revokeToken(
  config: XOAuthConfig,
  token: string,
  tokenType: "access_token" | "refresh_token" = "access_token"
): Promise<void> {
  const body = new URLSearchParams({
    token,
    token_type_hint: tokenType,
    client_id: config.clientId,
  });

  await fetch(X_REVOKE_URL, {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body: body.toString(),
  });
}

export async function fetchXProfile(
  accessToken: string
): Promise<XUserProfile> {
  const res = await fetch(
    `${X_USERS_ME_URL}?user.fields=id,name,username,profile_image_url,verified`,
    { headers: { Authorization: `Bearer ${accessToken}` } }
  );

  if (!res.ok) {
    throw new Error(`Failed to fetch X profile (${res.status})`);
  }

  const json = await res.json();
  return json.data as XUserProfile;
}
