export interface SessionConfig {
  cookieName?: string;
  maxAge?: number; // seconds
  secure?: boolean;
  sameSite?: "strict" | "lax" | "none";
  path?: string;
  domain?: string;
}

const DEFAULT_CONFIG: Required<SessionConfig> = {
  cookieName: "jettauth",
  maxAge: 86400, // 24h
  secure: true,
  sameSite: "lax",
  path: "/",
  domain: "",
};

export function buildSessionCookie(
  token: string,
  config?: SessionConfig
): string {
  const c = { ...DEFAULT_CONFIG, ...config };
  const parts = [`${c.cookieName}=${token}`, `Path=${c.path}`, `Max-Age=${c.maxAge}`];
  if (c.secure) parts.push("Secure");
  parts.push("HttpOnly");
  parts.push(`SameSite=${c.sameSite}`);
  if (c.domain) parts.push(`Domain=${c.domain}`);
  return parts.join("; ");
}

export function buildClearCookie(config?: SessionConfig): string {
  const c = { ...DEFAULT_CONFIG, ...config };
  return `${c.cookieName}=; Path=${c.path}; Max-Age=0; HttpOnly`;
}

export function extractToken(
  cookieHeader: string | null,
  cookieName?: string
): string | null {
  if (!cookieHeader) return null;
  const name = cookieName ?? DEFAULT_CONFIG.cookieName;
  const match = cookieHeader
    .split(";")
    .map((c) => c.trim())
    .find((c) => c.startsWith(`${name}=`));
  return match ? match.slice(name.length + 1) : null;
}
