import { verifyJWT, type JettAuthClaims } from "./jwt";
import { extractToken } from "./session";

export interface MiddlewareConfig {
  publicRoutes?: string[];
  publicKey: Uint8Array;
  cookieName?: string;
  loginRedirect?: string;
}

export interface AuthResult {
  authenticated: boolean;
  claims: JettAuthClaims | null;
}

const DEFAULT_PUBLIC_ROUTES = [
  "/",
  "/login",
  "/callback/x",
  "/callback/wallet",
  "/api/auth/x",
  "/api/auth/x/callback",
  "/api/auth/wallet/verify",
  "/api/auth/refresh",
  "/pricing",
];

export function isPublicRoute(
  pathname: string,
  publicRoutes?: string[]
): boolean {
  const routes = publicRoutes ?? DEFAULT_PUBLIC_ROUTES;
  return routes.some((route) => {
    if (route.endsWith("*")) {
      return pathname.startsWith(route.slice(0, -1));
    }
    return pathname === route;
  });
}

export function authenticateRequest(
  cookieHeader: string | null,
  config: MiddlewareConfig
): AuthResult {
  const token = extractToken(cookieHeader, config.cookieName);
  if (!token) return { authenticated: false, claims: null };

  try {
    const claims = verifyJWT(token, config.publicKey);
    return { authenticated: true, claims };
  } catch {
    return { authenticated: false, claims: null };
  }
}

/**
 * Next.js middleware helper. Import and use in your middleware.ts:
 *
 * ```ts
 * import { createAuthMiddleware } from "@jettoptx/auth";
 *
 * export default createAuthMiddleware({
 *   publicKey: decodeBase64(process.env.JWT_PUBLIC_KEY!),
 *   loginRedirect: "/login",
 * });
 * ```
 */
export function createNextMiddlewareHandler(config: MiddlewareConfig) {
  return (request: {
    nextUrl: { pathname: string };
    headers: { get(name: string): string | null };
  }) => {
    const { pathname } = request.nextUrl;

    if (isPublicRoute(pathname, config.publicRoutes)) {
      return { type: "next" as const };
    }

    const cookieHeader = request.headers.get("cookie");
    const auth = authenticateRequest(cookieHeader, config);

    if (!auth.authenticated) {
      return {
        type: "redirect" as const,
        url: config.loginRedirect ?? "/login",
      };
    }

    return { type: "next" as const, claims: auth.claims };
  };
}
